import itertools, random, math, numpy as np

def prob(weights,p, ge=True):
    m=len(weights)
    total=0.0
    for mask in range(1<<m):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; k+=1
        if (s >= p - 1e-12 if ge else s>p):
            total += p**k*(1-p)**(m-k)
    return total

def sample_weights(m):
    xs=np.random.exponential(1,size=m)
    return (xs/xs.sum()).tolist()

