def circle_good_measure(points, weights, p, N=10000):
    ts=np.linspace(0,1,N,endpoint=False)
    vals=np.zeros(N)
    pts=np.array(points)
    for x,w in zip(pts,weights):
        # t such that x in [t,t+p) mod1 -> t in (x-p,x]
        # easier compute for each t
        diff=(x-ts)%1
        vals += w*((diff < p) | np.isclose(diff,p)) # half-open ignore
    return np.mean(vals>=p), vals.min(), vals.max()

