def cyclic_good_count(y,a):
    b=len(y); thr=a/b
    cnt=0; sums=[]
    for i in range(b):
        s=sum(y[(i+j)%b] for j in range(a))
        sums.append(s)
        if s>=thr-1e-12: cnt+=1
    return cnt,sums
