def hyper_good(b,a,h):
    # h positives each 1/h
    thr=a/b
    req=math.ceil(thr*h - 1e-12)
    total=math.comb(b,a)
    cnt=0
    for j in range(req, min(a,h)+1):
        if a-j<=b-h:
            cnt+=math.comb(h,j)*math.comb(b-h,a-j)
    return cnt/total, req
